function monthStart(value) {
  if (!value) return null;
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return null;
  return `${date.getUTCFullYear()}-${String(date.getUTCMonth() + 1).padStart(2, '0')}-01`;
}

function ruleForMacro(macro) {
  switch (macro) {
    case 'bookkeeping':
      return ['bookkeeping_complete_required', 'pending_bookkeeping_completion'];
    case 'payroll':
      return ['payroll_processed_required', 'pending_payroll_processed'];
    case 'tax':
      return ['tax_filed_or_extended_required', 'pending_tax_completion'];
    case 'advisory':
      return ['advisory_delivery_review_required', 'pending_advisory_review'];
    default:
      return ['manual_review_required', 'pending_manual_review'];
  }
}

const revenueLines = $('Fetch Revenue Lines').all().map((item) => item.json);
const invoices = $('Fetch Invoices').all().map((item) => item.json);
const invoiceById = Object.fromEntries(invoices.map((invoice) => [invoice.anchor_invoice_id, invoice]));

const rows = revenueLines.map((line) => {
  const invoice = invoiceById[line.anchor_invoice_id] ?? {};
  const [recognitionRule, recognitionStatus] = ruleForMacro(line.macro_service_type);
  return {
    revenue_event_key: `rev_${line.anchor_line_item_id}`,
    anchor_line_item_id: line.anchor_line_item_id,
    anchor_invoice_id: line.anchor_invoice_id,
    anchor_relationship_id: line.anchor_relationship_id ?? null,
    macro_service_type: line.macro_service_type,
    source_amount: Number(line.revenue_amount ?? 0),
    recognized_amount: 0,
    recognition_status: recognitionStatus,
    recognition_rule: recognitionRule,
    candidate_period_month: monthStart(invoice.issue_date ?? invoice.due_date),
    recognition_date: null,
    recognition_period_month: null,
    trigger_source: null,
    trigger_reference: null,
    notes: 'Candidate generated from Anchor invoice line classification. Not recognized until completion trigger is applied.',
    loaded_at: new Date().toISOString(),
  };
});

const byStatus = rows.reduce((acc, row) => {
  acc[row.recognition_status] = (acc[row.recognition_status] ?? 0) + 1;
  return acc;
}, {});
const sourceAmount = rows.reduce((sum, row) => sum + Number(row.source_amount ?? 0), 0);
return [
  {
    json: {
      rows,
      summary: {
        candidateCount: rows.length,
        sourceAmount: Math.round(sourceAmount * 100) / 100,
        byStatus,
      },
    },
  },
];

const rows = $input.all().map((item) => item.json);
const byStatus = rows.reduce((acc, row) => {
  acc[row.recognition_status] = (acc[row.recognition_status] ?? 0) + 1;
  return acc;
}, {});
const byRule = rows.reduce((acc, row) => {
  acc[row.recognition_rule] = (acc[row.recognition_rule] ?? 0) + 1;
  return acc;
}, {});
const sourceAmount = rows.reduce((sum, row) => sum + Number(row.source_amount ?? 0), 0);
const recognizedAmount = rows.reduce((sum, row) => sum + Number(row.recognized_amount ?? 0), 0);
return [
  {
    json: {
      status: 'ok',
      upsertedRevenueEventCount: rows.length,
      sourceAmount: Math.round(sourceAmount * 100) / 100,
      recognizedAmount: Math.round(recognizedAmount * 100) / 100,
      byStatus,
      byRule,
      sample: rows.slice(0, 10),
    },
  },
];
